{"type":"assistant","message":{"content":[{"id":"tooluse_WxAFVyvKnjWqr5CXZbV7Fo","input":{"file_path":"/Users/tomato/Documents/potato/project/YFD/yfd-agent-consensus/results/agent_consensus_batch/default_run/task_27_atr_volatility_breakout/revised/claudecode/atr_breakout_analysis.py","content":"#!/usr/bin/env python3\n\"\"\"\nATR波动率扩张突破识别\n筛选创业板中波动率扩张的股票\n\"\"\"\nfrom mootdx.quotes import Quotes\nimport pandas as pd\nimport numpy as np\nfrom datetime import datetime, timedelta\n\ndef calculate_atr(df, period=14):\n    \"\"\"\n    计算ATR（Average True Range）使用Wilder平滑法\n    \"\"\"\n    # 计算True Range\n    high = df['high'].values\n    low = df['low'].values\n    close = df['close'].values\n\n    tr = np.zeros(len(df))\n    for i in range(len(df)):\n        if i == 0:\n            tr[i] = high[i] - low[i]\n        else:\n            tr[i] = max(\n                high[i] - low[i],\n                abs(high[i] - close[i-1]),\n                abs(low[i] - close[i-1])\n            )\n\n    # Wilder平滑法计算ATR\n    atr = np.zeros(len(df))\n    atr[period-1] = np.mean(tr[:period])\n\n    for i in range(period, len(df)):\n        atr[i] = (atr[i-1] * (period - 1) + tr[i]) / period\n\n    return atr\n\ndef analyze_stock(client, code, target_date='2024-09-09'):\n    \"\"\"\n    分析单只股票是否符合ATR突破条件\n    \"\"\"\n    try:\n        # 获取足够的历史数据（80日+额外缓冲）\n        bars = client.bars(symbol=code, frequency=9, offset=120)\n\n        if bars is None or len(bars) < 80:\n            return None\n\n        # 确保datetime列存在且为索引\n        if 'datetime' in bars.columns:\n            bars['datetime'] = pd.to_datetime(bars['datetime'])\n            bars = bars.sort_values('datetime')\n\n        # 计算ATR\n        atr = calculate_atr(bars, period=14)\n        bars['atr'] = atr\n\n        # 找到目标日期或最接近的日期\n        bars['date_str'] = bars['datetime'].dt.strftime('%Y-%m-%d')\n        target_idx = bars[bars['date_str'] <= target_date].index\n\n        if len(target_idx) == 0:\n            return None\n\n        current_idx = target_idx[-1]\n\n        # 确保有足够的历史数据\n        if current_idx < 60:\n            return None\n\n        # 获取当前ATR\n        current_atr = bars.loc[current_idx, 'atr']\n\n        if current_atr == 0 or np.isnan(current_atr):\n            return None\n\n        # 计算近60日ATR的80分位数\n        atr_60d = bars.loc[current_idx-59:current_idx, 'atr'].values\n        atr_80pct = np.percentile(atr_60d[atr_60d > 0], 80)\n\n        # 条件1: ATR突破80分位数\n        if current_atr <= atr_80pct:\n            return None\n\n        # 条件2: 收盘价突破近20日最高价\n        if current_idx < 20:\n            return None\n\n        high_20d = bars.loc[current_idx-20:current_idx-1, 'high'].max()\n        current_close = bars.loc[current_idx, 'close']\n\n        if current_close <= high_20d:\n            return None\n\n        # 条件3: 成交量 > 20日均量的2倍\n        vol_20d_avg = bars.loc[current_idx-20:current_idx-1, 'volume'].mean()\n        current_vol = bars.loc[current_idx, 'volume']\n\n        if current_vol <= vol_20d_avg * 2:\n            return None\n\n        # 条件4: 收阳且涨幅>3%\n        current_open = bars.loc[current_idx, 'open']\n\n        if current_close <= current_open:\n            return None\n\n        pct_change = (current_close - current_open) / current_open * 100\n\n        if pct_change <= 3.0:\n            return None\n\n        # 所有条件满足，返回结果\n        breakout_date = bars.loc[current_idx, 'date_str']\n\n        return {\n            'code': code,\n            'atr': round(current_atr, 2),\n            'atr_80pct': round(atr_80pct, 2),\n            'breakout_date': breakout_date,\n            'pct_change': round(pct_change, 2)\n        }\n\n    except Exception as e:\n        print(f\"处理股票 {code} 时出错: {e}\")\n        return None\n\ndef main():\n    print(\"初始化mootdx客户端...\")\n    client = Quotes.factory(market='std')\n\n    print(\"获取创业板股票列表...\")\n    stocks = client.stocks(market=0)\n    chinext = stocks[stocks['code'].str.startswith(('300', '301'))]\n\n    print(f\"找到 {len(chinext)} 只创业板股票\")\n    print(\"开始筛选符合条件的股票...\")\n\n    results = []\n    total = len(chinext)\n\n    for idx, row in chinext.iterrows():\n        code = row['code']\n        if (idx + 1) % 50 == 0:\n            print(f\"进度: {idx + 1}/{total}\")\n\n        result = analyze_stock(client, code)\n        if result:\n            results.append(result)\n            print(f\"✓ 找到符合条件的股票: {code}\")\n\n    print(f\"\\n筛选完成! 共找到 {len(results)} 只符合条件的股票\")\n\n    # 写入结果文件\n    output_file = 'atr_breakout.txt'\n    with open(output_file, 'w', encoding='utf-8') as f:\n        if len(results) == 0:\n            f.write(\"无符合条件的股票\\n\")\n        else:\n            f.write(\"股票代码,截至2024-09-09的ATR,ATR的60日80分位数,突破日期,当日涨幅(%)\\n\")\n            for r in results:\n                f.write(f\"{r['code']},{r['atr']},{r['atr_80pct']},{r['breakout_date']},{r['pct_change']}\\n\")\n\n    print(f\"结果已写入 {output_file}\")\n\n    return results\n\nif __name__ == '__main__':\n    results = main()\n"},"name":"Write","type":"tool_use"}],"id":"d2e87fec-75cf-49af-a18a-7ad23e26e1c8","model":"claude-sonnet-4-6","role":"assistant","stop_reason":null,"stop_sequence":null,"type":"message","usage":{"cache_creation_input_tokens":817,"cache_read_input_tokens":0,"input_tokens":15159,"output_tokens":0},"context_management":null},"parent_tool_use_id":null,"session_id":"b4770a80-3914-4ab4-93c2-17453425ba26","uuid":"40b962f6-b1bf-4934-92fd-aa828d68b438"}
